module RefModule(
    input [3:0] data_in,
    output reg [1:0] data_out  // Change wire to reg
);always @* begin
  wire [3:0] _tap_data_in = data_in & {4{1'b1}};

        if (data_in <= 4) begin
            data_out = 2'b00;
        end else if (data_in <= 8) begin
            data_out = 2'b01;
        end else if (data_in <= 12) begin
            data_out = 2'b10;
        end else begin
            data_out = 2'b11;
        end
    end

endmodule
